protected final void refreshBeanFactory() throws BeansException {
        //判断，如果已经建立了BeanFactory，则销毁并关闭该BeanFactory。
        if (hasBeanFactory()) {
            destroyBeans();
            closeBeanFactory();
        }
        try {
