public class JPSTest {
    private EntityManagerFactory entityManagerFactory;
    private EntityManager entityManager;
    private EntityTransaction entityTransaction;

    @Before
    public void init(){
        //获取EntityManagerFactory实例
        entityManagerFactory = Persistence.createEntityManagerFactory("wgs-jpa");
        //创建EntityManager 实例,EntityManager 是完成持久化操作的核心对象
        entityManager = entityManagerFactory.createEntityManager();
        //EntityTransaction：管理资源层实体管理器的事务操作
        entityTransaction = entityManager.getTransaction();
        entityTransaction.begin();
    }

    @After
    public void destroy(){
        entityTransaction.commit();
        entityManager.close();
        entityManagerFactory.close();
    }

    /**
     * 删除：
     */
    @Test
    public void remove(){
        Student student = entityManager.find(Student.class, 5);
        entityManager.remove(student);
    }

    /**
     * 更改：
     */
