    public void testUpdate(){
        Student student = entityManager.find(Student.class, 4);
        student.setName("wgs");
    }
    /**
     * 增：将对象持久化保存到数据库
     * 注意：此处实体类的主键id设置为自增：strategy = GenerationType.IDENTITY
     *       数据库中的id一定也要设置为自增，否则持久化时就会抛PersistenceException异常
     */
    @Test
    public void testSave(){
        Student student = new Student();
        student.setAge(55);
        student.setName("dd");
        System.out.println(student.getId());
        entityManager.persist(student);
    }
    /**
     * 查找2：EntityManager.getReference(Entity.class, id)，
     * 类似于hibernate的load方法,延迟加载，没有查到数据时返回异常；
