**（1）实体类Student：**

```
package com.wgs.jpademo;

import javax.persistence.*;

/**
 * @author GenshenWang.nomico
 * @date 2017/12/29.
 */
@NamedQuery(name = "wgsNamedQuery", query="FROM Student s WHERE s.age = ?1")
@Entity
public class Student {
    private int id;
    private String name;
    private int age;


    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    public int getId() {
        return id;
    }

    public void setId(int id) {
        this.id = id;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public int getAge() {
        return age;
    }

    public void setAge(int age) {
        this.age = age;
    }

    public Student() {
    }

    public Student(String name, int age) {
        this.name = name;
        this.age = age;
    }

    @Override
    public String toString() {
        return "Student's name : " + name +", age:" + age;
    }
}
```

