    public static void main(String[] args) {
        //模拟用户选择
        String select = "run";
        TravelContext context = new TravelContext(select);
        context.getTravelWays();

        select = "air";
        context = new TravelContext(select);
        context.getTravelWays();

        select = "train";
        context = new TravelContext(select);
