### Java代码实现一个简单的RPC框架

**服务端：**   
 服务端是暴露服务。   
 在对Socket操作时，先读后写。

> **读：**先从Socket连接中获取客户端的所要调用的远程服务的方法及请求参数等信息；   
>  **写：**服务端的Server Stub调用服务端的真正的远程服务处理函数处理后获取结果，再将结果写回Socket。

核心代码：

```
/**
     * 暴露服务
     * @param service 服务实现
     * @param port 服务端口
     * @throws Exception
     */
    public static void export(final Object service, int port) throws Exception{     
        ServerSocket ss = new ServerSocket(port);
        Socket socket = ss.accept();

        /**  socket中读取参数等信息并反序列化封装成对象  **/
        ObjectInputStream in = new ObjectInputStream(socket.getInputStream());
        //读取一个String类型的值 ： method即为String类型的
        String methodName = in.readUTF();
        //获取方法上定义的泛型参数 
        Class<?>[] parameterTypes = (Class<?>[])in.readObject();
        //获取参数
        Object[] arguments = (Object[])in.readObject();

        //调用接口中所需要的方法
        Method method = service.getClass().getMethod(methodName, parameterTypes);
        //处理结果
        Object result = method.invoke(service, arguments);

        /** 将结果序列化写回socket **/
        ObjectOutputStream out = new ObjectOutputStream(socket.getOutputStream());
        out.writeObject(result);



    }
```

**客户端：**   
 客户端是引用服务。   
 在对Socket操作时是先写后读。

> 写：将服务端想要调用的远程服务的方法名，参数等信息写入Socket；   
>  读： 从Socket中读取服务端的处理结果。

核心代码：

```
/**
     * 引用服务
     * @param service
     * @param port
     * @throws Exception
     */
    @SuppressWarnings("unchecked")
    public static <T> T refer(final Class<T> interfaceClass, final String host, int port) throws Exception{

        return (T)Proxy.newProxyInstance(interfaceClass.getClassLoader(), 
                new Class<?>[]{interfaceClass},
                new InvocationHandler() {

                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {

                            Socket socket = new Socket(host, port);
                            /** 先将客户端想要调用的远程服务信息及参数写入socket **/
                            ObjectOutputStream out = new ObjectOutputStream(socket.getOutputStream());
                            //方法名
                            out.writeUTF(method.getName());
                            //方法上的泛型参数
                            out.writeObject(method.getParameterTypes());
                            //调用的参数
                            out.writeObject(args);

                            /** 获取调用的远程服务处理的结果  **/
                            ObjectInputStream in = new ObjectInputStream(socket.getInputStream());
                            Object result = in.readObject();


                            return null;
                    }
                });

    }
```

**最原始的RPC功能的实现：**

```
package com.wgs.rpc.framework;

import java.io.IOException;
import java.io.ObjectInputStream;
import java.io.ObjectOutputStream;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;
import java.net.ServerSocket;
import java.net.Socket;

/**
 * 
 * @author GenshenWang.nomico
 *
 */
public class RPCFramework {

    /**
     * 暴露服务
     * @param service 
     * @param port
     * @throws Exception
     */
    public static void export(final Object service, int port) throws Exception{
        if (service == null){
            throw new IllegalArgumentException(" service instance == null");
        }
        if (port <= 0 || port > 65535){
            throw new IllegalArgumentException("Invalid port " + port);
        }
        System.out.println("Export service: " + service.getClass().getName() + "on port :" + port);

        //监听端口
        ServerSocket server = new ServerSocket(port);
        for(;;){
            try{
                final Socket socket = server.accept();

                new Thread(new Runnable(){

                    @Override
                    public void run() {
                        try {
                            /**  socket中读取参数等信息并反序列化封装成对象  **/
                            ObjectInputStream in = new ObjectInputStream(socket.getInputStream());

                            try {
                                //获取方法名
                                String methodName = in.readUTF();
                                //获取方法上泛型
                                Class<?>[] parameterTypes = (Class<?>[])in.readObject();
                                //获取的参数
                                Object[] arguments = (Object[])in.readObject();

                                /**  将处理结果序列化后输出到socket  **/
                                ObjectOutputStream out = new ObjectOutputStream(socket.getOutputStream());
                                try {
                                    //获取要调用的方法
                                    Method method = service.getClass().getMethod(methodName, parameterTypes);
                                    //将参数传入，进行处理
                                    Object result = method.invoke(service, arguments);

                                    //将结果序列化输出
                                    out.writeObject(result);
                                } catch(Throwable t){
                                    out.writeObject(t);
                                } finally{
                                    out.close();
                                }
                            } catch(Exception e) {
                                e.printStackTrace();
                            } finally {
                                in.close();
                            }

                        } catch(Exception e){
                            e.printStackTrace();
                        } finally {
                            try {
                                socket.close();
                            } catch (IOException e) {
                                e.printStackTrace();
                            }
                        }

                    }

                }).start();

            }catch(Exception e){
                e.printStackTrace();
            }
        }
    }

    /**
     * 引用远程服务
     * @param interfaceClass 调用的接口
     * @param host IP
     * @param port 端口
     * @return
     */
    @SuppressWarnings("unchecked")
    public static <T> T refer(final Class<T> interfaceClass, final String host, final int port){


        return (T) Proxy.newProxyInstance(interfaceClass.getClassLoader(), 
                new Class<?>[]{interfaceClass}, 
                new InvocationHandler(){

                    @Override
                    public Object invoke(Object proxy, Method method, Object[] argumens) throws Throwable {

                         Socket socket = new Socket(host, port);

                        try{
                            /** 写：先将要调用的远程服务，参数等信息序列化输出到socket **/
                            ObjectOutputStream out = new ObjectOutputStream(socket.getOutputStream());

                            try {
                                //将方法名写入socket
                                out.writeUTF(method.getName());
                                //将泛型类型写入socket
                                out.writeObject(method.getParameterTypes());
                                //将参数写入socket
                                out.writeObject(argumens);

                                /** 读：从socket流中读取调用的远程服务的结果 **/
                                ObjectInputStream in = new ObjectInputStream(socket.getInputStream());
                                try {
                                    Object result = in.readObject();
                                     if (result instanceof Throwable) {  
                                        throw (Throwable) result;  
                                     }  
                                    return result;
                                }finally{
                                    in.close();
                                }
                            } finally{
                                out.close();
                            }
                        } finally{
                            socket.close();
                        }
                    }
                });
    }
}
```

