public class ChatServer {

	public void ServerService(){
		ServerSocket ss = null;
		Socket socket = null;
		DataOutputStream out = null;
		DataInputStream in = null;
		try {
			ss = new ServerSocket(9090);
			System.out.println("服务器开启监听");
			socket = ss.accept();

			//InputStream用来接收客户端的消息
			in = new DataInputStream(socket.getInputStream());
			//OutputStream流用来发送反馈信息到客户端
			out = new DataOutputStream(socket.getOutputStream());			

			Scanner sc =  new Scanner(System.in);
			while(true){

				//读取来自客户端信息
				String recvMsgFromServer = in.readUTF();
				System.out.println("【From客户端】" + recvMsgFromServer);		

				//控制面板中输入信息并发送给客户端
				String inputMsg = sc.nextLine();
				//System.out.println("【服务器端输入信息：】" + inputMsg);
				out.writeUTF(inputMsg);

			}
		} catch (UnknownHostException e) {
			e.printStackTrace();
		} catch (IOException e) {
			e.printStackTrace();
		}finally{
			if(ss != null){
				try {
					ss.close();
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			if(in != null){
				try {
					in.close();
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			if(out != null){
				try {
					out.close();
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			if(socket != null){
				try {
					socket.close();
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
		}

	}

	public static void main(String[] args) {
		System.out.println("服务器正在启动。。。");
		new ChatServer().ServerService();
	}

}
