	        for (Entry<K,V> e = getFirstEntry(); e != null; e = successor(e))
	            if (valEquals(value, e.value))
	                return true;
	        return false;
	    }

	    //获取指定键key对应的value值
	    //先获取指定的结点Entry，再返回对应的结点的值
	    public V get(Object key) {
