	   //方式一:有比较器的情况:getEntryUsingComparator
	    final Entry<K,V> getEntryUsingComparator(Object key) {
	        K k = (K) key;
	        //获取比较器
	        Comparator<? super K> cpr = comparator;
	        //比较器不为空
	        if (cpr != null) {
	            Entry<K,V> p = root;//获取根结点
	            //遍历树
	            while (p != null) {
	            	//判断当前结点与指定结点的key大小,直接调用比较器中方法compare(a,b)
	                int cmp = cpr.compare(k, p.key);
	                //当前结点key 大于 指定key,遍历下个左子节点
	                if (cmp < 0)
	                    p = p.left;
	                //当前结点key大于指定key,遍历下个右子节点
	                else if (cmp > 0)
	                    p = p.right;
	                else
	                    return p;//相等
	            }
	        }
	        return null;//没找到
	    }

	    /**
	     * 寻找key对应的结点。
	     * 如果没有直接对应的节点，
	     * 			若都大于 key，返回最小的结点
	     * 			若都小于key， 返回最大的结点
	     */
	    final Entry<K,V> getCeilingEntry(K key) {
	        Entry<K,V> p = root;
	        while (p != null) {//遍历树
	            int cmp = compare(key, p.key);//比较指定key与当前结点的key
	            //当前结点key > 指定key
	            if (cmp < 0) {
	                if (p.left != null)
	                    p = p.left;
	                else
	                    return p;//返回最小的结点
	            } 
	            //当前结点key < 指定key
	            else if (cmp > 0) {
	                if (p.right != null) {
	                    p = p.right;
	                } else {
	                    Entry<K,V> parent = p.parent;
	                    Entry<K,V> ch = p;
	                    while (parent != null && ch == parent.right) {
	                        ch = parent;
	                        parent = parent.parent;
	                    }
	                    return parent;
	                }
	            } else
	                return p;
	        }
	        return null;
	    }

	    /**
	     * Gets the entry corresponding to the specified key; if no such entry
	     * exists, returns the entry for the greatest key less than the specified
	     * key; if no such entry exists, returns {@code null}.
	     */
	    final Entry<K,V> getFloorEntry(K key) {
	        Entry<K,V> p = root;
	        while (p != null) {
	            int cmp = compare(key, p.key);
	            if (cmp > 0) {
	                if (p.right != null)
	                    p = p.right;
	                else
	                    return p;
	            } else if (cmp < 0) {
	                if (p.left != null) {
	                    p = p.left;
	                } else {
	                    Entry<K,V> parent = p.parent;
	                    Entry<K,V> ch = p;
	                    while (parent != null && ch == parent.left) {
	                        ch = parent;
	                        parent = parent.parent;
	                    }
	                    return parent;
	                }
	            } else
	                return p;

	        }
	        return null;
	    }

	    /**
	     * Gets the entry for the least key greater than the specified
	     * key; if no such entry exists, returns the entry for the least
	     * key greater than the specified key; if no such entry exists
	     * returns {@code null}.
	     */
	    final Entry<K,V> getHigherEntry(K key) {
	        Entry<K,V> p = root;
	        while (p != null) {
	            int cmp = compare(key, p.key);
	            if (cmp < 0) {
	                if (p.left != null)
	                    p = p.left;
	                else
	                    return p;
	            } else {
	                if (p.right != null) {
	                    p = p.right;
	                } else {
	                    Entry<K,V> parent = p.parent;
	                    Entry<K,V> ch = p;
	                    while (parent != null && ch == parent.right) {
	                        ch = parent;
	                        parent = parent.parent;
	                    }
	                    return parent;
	                }
	            }
	        }
	        return null;
	    }

	    /**
	     * Returns the entry for the greatest key less than the specified key; if
	     * no such entry exists (i.e., the least key in the Tree is greater than
	     * the specified key), returns {@code null}.
	     */
	    final Entry<K,V> getLowerEntry(K key) {
	        Entry<K,V> p = root;
	        while (p != null) {
	            int cmp = compare(key, p.key);
	            if (cmp > 0) {
	                if (p.right != null)
	                    p = p.right;
	                else
	                    return p;
	            } else {
	                if (p.left != null) {
	                    p = p.left;
	                } else {
	                    Entry<K,V> parent = p.parent;
	                    Entry<K,V> ch = p;
	                    while (parent != null && ch == parent.left) {
	                        ch = parent;
	                        parent = parent.parent;
	                    }
	                    return parent;
	                }
	            }
	        }
	        return null;
	    }

	    /**
	     * 按指定的排序算法存储值。如果先前有key对应的值，就覆盖
	     */
	    public V put(K key, V value) {
	    	//t表示二叉树的当前结点
	        Entry<K,V> t = root;
	        //t为null，即为空树，直接插入元素
	        if (t == null) {
	            compare(key, key); //自己与自己比较大小
	            root = new Entry<>(key, value, null);//根据指定的key-value键值对直接创建一个Entry结点,赋给root
	            size = 1;//大小设为1
	            modCount++;//修改次数+1
	            return null;
	        }
	        int cmp;//返回的排序结果
	        Entry<K,V> parent;//父节点
	        // split comparator and comparable paths
	        Comparator<? super K> cpr = comparator;//指定的排序算法插入元素
	        //指定了排序算法，就用这个算法创建Treemap集合
	        if (cpr != null) {
	            do {
	                parent = t;//parent指向上次循环后的t  
	                //比较新增节点的key和当前节点key(t.key)的大小  
	                cmp = cpr.compare(key, t.key);
	                //cmp返回值小于0:key  <  t.key
	                //表示新增节点的key小于当前节点的key(t.key)，则以当前节点的左子节点作为新的当前节点  
	                if (cmp < 0)
	                    t = t.left;
	                //同上理
	                else if (cmp > 0)
	                    t = t.right;
	                else
	                    return t.setValue(value);//key已经存在，覆盖原来的值
	            } while (t != null);
	        }
	        //没有指定排序算法,按默认的排序算法进行处理
	        else {
	            if (key == null)
	                throw new NullPointerException();
	            Comparable<? super K> k = (Comparable<? super K>) key;
	            do {
	                parent = t;
	                cmp = k.compareTo(t.key);
	                if (cmp < 0)
	                    t = t.left;
	                else if (cmp > 0)
	                    t = t.right;
	                else
	                    return t.setValue(value);
	            } while (t != null);
	        }
	        //将新增的结点当做parent的子结点
	        Entry<K,V> e = new Entry<>(key, value, parent);
	        //如果新增节点的key小于parent的key，则当做左子节点  
	        if (cmp < 0)
	            parent.left = e;
	      //如果新增节点的key大于parent的key，则当做右子节点  
	        else
	            parent.right = e;
	        /*  
             *  上面已经完成了排序二叉树的的构建，将新增节点插入该树中的合适位置  
             *  下面fixAfterInsertion()方法就是对这棵树进行调整、平衡
             */  
	        fixAfterInsertion(e);
	        size++;
	        modCount++;
	        return null;
	    }

	    //删除key对应的结点
	    public V remove(Object key) {
	        Entry<K,V> p = getEntry(key);//获取key对应的结点
	        if (p == null)
	            return null;

	        V oldValue = p.value;//获取结点对应的值
	        deleteEntry(p);//删除
	        return oldValue;//返回原先值 
	    }

	    //清空
	    public void clear() {
	        modCount++;
	        size = 0;
	        root = null;
	    }

	    //浅拷贝
	    public Object clone() {
	        TreeMap<K,V> clone = null;
	        try {
	            clone = (TreeMap<K,V>) super.clone();
	        } catch (CloneNotSupportedException e) {
	            throw new InternalError();
	        }

	        // Put clone into "virgin" state (except for comparator)
	        clone.root = null;
	        clone.size = 0;
	        clone.modCount = 0;
	        clone.entrySet = null;
	        clone.navigableKeySet = null;
	        clone.descendingMap = null;

	        // Initialize clone with our mappings
	        try {
	            clone.buildFromSorted(size, entrySet().iterator(), null, null);
	        } catch (java.io.IOException cannotHappen) {
	        } catch (ClassNotFoundException cannotHappen) {
	        }

	        return clone;
	    }

