	            if (!(o instanceof Map.Entry))
	                return false;
	            Map.Entry<K,V> entry = (Map.Entry<K,V>) o;
	            V value = entry.getValue();
	            Entry<K,V> p = getEntry(entry.getKey());
	            if (p != null && valEquals(p.getValue(), value)) {
	                deleteEntry(p);
	                return true;
	            }
	            return false;
	        }

	        public int size() {
	            return TreeMap.this.size();
	        }

	        public void clear() {
	            TreeMap.this.clear();
	        }
	    }

