	    /*********************************************重点***********************************************************************************/
	    /**
	     * 红黑树的操作在此 是重点
	     * 
	     */
	    private static final boolean RED   = false;
	    private static final boolean BLACK = true;

	    //树中结点的内部结构.Entry内部结构就是树
	    static final class Entry<K,V> implements Map.Entry<K,V> {
	        K key;
	        V value;
	        Entry<K,V> left = null;//左结点
	        Entry<K,V> right = null;//右结点
	        Entry<K,V> parent;//父节点
	        boolean color = BLACK;// 默认是黑色  BLACK = true 

	        //构造器
	        Entry(K key, V value, Entry<K,V> parent) {
	            this.key = key;
	            this.value = value;
	            this.parent = parent;
	        }
	        //获取键
	        public K getKey() {
	            return key;
	        }
	        //获取键对应的值
	        public V getValue() {
	            return value;
	        }
	        //设置值，有旧值就覆盖，返回旧值
	        public V setValue(V value) {
	            V oldValue = this.value;
	            this.value = value;
	            return oldValue;
	        }
	        public boolean equals(Object o) {
	            if (!(o instanceof Map.Entry))
	                return false;
	            Map.Entry<?,?> e = (Map.Entry<?,?>)o;

	            return valEquals(key,e.getKey()) && valEquals(value,e.getValue());
	        }

	        public int hashCode() {
	            int keyHash = (key==null ? 0 : key.hashCode());
	            int valueHash = (value==null ? 0 : value.hashCode());
	            return keyHash ^ valueHash;
	        }

	        public String toString() {
	            return key + "=" + value;
	        }
	    }

	    //排序的第一个结点(最左的那个结点)
	    final Entry<K,V> getFirstEntry() {
	        Entry<K,V> p = root;
	        if (p != null)
	            while (p.left != null)
	                p = p.left;
	        return p;
	    }

	    //排序的最后一个结点(最右的那个结点)
	    final Entry<K,V> getLastEntry() {
	        Entry<K,V> p = root;
	        if (p != null)
	            while (p.right != null)
	                p = p.right;
	        return p;
	    }

	    /**
	     * t 结点的继承者 
	     * ???
	     */
	    static <K,V> TreeMap.Entry<K,V> successor(Entry<K,V> t) {
	        if (t == null)
	            return null;
	        else if (t.right != null) {
	            Entry<K,V> p = t.right;
	            while (p.left != null)
	                p = p.left;
	            return p;
	        } else {
	            Entry<K,V> p = t.parent;
	            Entry<K,V> ch = t;
	            while (p != null && ch == p.right) {
	                ch = p;
	                p = p.parent;
	            }
	            return p;
	        }
	    }

	    /**
	     * t 结点的前驱
	     */
	    static <K,V> Entry<K,V> predecessor(Entry<K,V> t) {
	        if (t == null)
	            return null;
	        else if (t.left != null) {
	            Entry<K,V> p = t.left;
	            while (p.right != null)
	                p = p.right;
	            return p;
	        } else {
	            Entry<K,V> p = t.parent;
	            Entry<K,V> ch = t;
	            while (p != null && ch == p.left) {
	                ch = p;
	                p = p.parent;
	            }
	            return p;
	        }
	    }

	    //查看p结点的颜色，null 是BLACk
	    private static <K,V> boolean colorOf(Entry<K,V> p) {
	        return (p == null ? BLACK : p.color);
	    }
	    //查看p结点的父结点
	    private static <K,V> Entry<K,V> parentOf(Entry<K,V> p) {
	        return (p == null ? null: p.parent);
	    }
	    /**
	     * 设置结点的颜色，在红黑树中，它是依靠节点的颜色来维持平衡的。
	     */
	    private static <K,V> void setColor(Entry<K,V> p, boolean c) {
	        if (p != null)
	            p.color = c;
	    }
	    //查看p结点的left结点
	    private static <K,V> Entry<K,V> leftOf(Entry<K,V> p) {
	        return (p == null) ? null: p.left;
	    }
	    // 查看p结点的right结点
	    private static <K,V> Entry<K,V> rightOf(Entry<K,V> p) {
	        return (p == null) ? null: p.right;
	    }

	    /** From CLR */
	    /**
	     * 所谓左旋转，就是将新增节点（N）当做其父节点（P），
	     * 将其父节点P当做新增节点（N）的左子节点。即：G.left ---> N ,N.left ---> P。
	     * @param p
	     */
	    private void rotateLeft(Entry<K,V> p) {  
	        if (p != null) {  
	            //获取P的右子节点，其实这里就相当于新增节点N（情况四而言）  
	            Entry<K,V> r = p.right;  
	            //将R的左子树设置为P的右子树  
	            p.right = r.left;  
	            //若R的左子树不为空，则将P设置为R左子树的父亲  
	            if (r.left != null)  
	                r.left.parent = p;  
	            //将P的父亲设置R的父亲  
	            r.parent = p.parent;  
	            //如果P的父亲为空，则将R设置为跟节点  
	            if (p.parent == null)  
	                root = r;  
	            //如果P为其父节点（G）的左子树，则将R设置为P父节点(G)左子树  
	            else if (p.parent.left == p)  
	                p.parent.left = r;  
	            //否则R设置为P的父节点（G）的右子树  
	            else  
	                p.parent.right = r;  
	            //将P设置为R的左子树  
	            r.left = p;  
	            //将R设置为P的父节点  
	            p.parent = r;  
	        }  
	    } 

	    /** From CLR */
	    /**
	     * 所谓右旋转即，P.right ---> G、G.parent ---> P。
	     * @param p
	     */
	    private void rotateRight(Entry<K,V> p) {  
	        if (p != null) {  
	            //将L设置为P的左子树  
	            Entry<K,V> l = p.left;  
	            //将L的右子树设置为P的左子树  
	            p.left = l.right;  
	            //若L的右子树不为空，则将P设置L的右子树的父节点  
	            if (l.right != null)   
	                l.right.parent = p;  
	            //将P的父节点设置为L的父节点  
	            l.parent = p.parent;  
	            //如果P的父节点为空，则将L设置根节点  
	            if (p.parent == null)  
	                root = l;  
	            //若P为其父节点的右子树，则将L设置为P的父节点的右子树  
	            else if (p.parent.right == p)  
	                p.parent.right = l;  
	            //否则将L设置为P的父节点的左子树  
	            else   
	                p.parent.left = l;  
	            //将P设置为L的右子树  
	            l.right = p;  
	            //将L设置为P的父节点  
	            p.parent = l;  
	        }  
	    }  

	    /** From CLR */
	    /**
	     * public V put(K key, V value) {...}  345行
	     * 				代码中do{}代码块是实现排序二叉树的核心算法，通过该算法我们可以确认新增节点在该树的正确位置。
	     * 找到正确位置后将插入即可，这样做了其实还没有完成，
	     * 因为TreeMap的底层实现是红黑树，红黑树是一棵平衡排序二叉树，普通的排序二叉树可能会出现失衡的情况，
	     * 所以下一步就是要进行调整。
	     * fixAfterInsertion(e); 调整的过程务必会涉及到红黑树的左旋、右旋、着色三个基本操作
	     * @param x
	     */
	    private void fixAfterInsertion(Entry<K,V> x) {
	        x.color = RED;//新增节点的颜色为红色  
	        //循环 直到 x不是根节点，且x的父节点不为红色  
	        while (x != null && x != root && x.parent.color == RED) {
	        	 //如果X的父节点（P）是其父节点的父节点（G）的左节点  
	        	if (parentOf(x) == leftOf(parentOf(parentOf(x)))) {
	        		 //获取X的叔节点(U)  
	        		Entry<K,V> y = rightOf(parentOf(parentOf(x)));
	        		 //如果X的叔节点（U） 为红色（情况三）  
	        		if (colorOf(y) == RED) {
	        			//将X的父节点（P）设置为黑色  
	        			setColor(parentOf(x), BLACK);
	        			//将X的叔节点（U）设置为黑色  
	                    setColor(y, BLACK);
	                  //将X的父节点的父节点（G）设置红色  
	                    setColor(parentOf(parentOf(x)), RED);
	                    x = parentOf(parentOf(x));
	                } else {
	                	 //如果X的叔节点（U为黑色）；这里会存在两种情况（情况四、情况五）  
	                    if (x == rightOf(parentOf(x))) {
	                    	//将X的父节点作为X  
	                    	x = parentOf(x);
	                    	//右旋转  
	                        rotateLeft(x);
	                    }
	                    //（情况五）  
                        //将X的父节点（P）设置为黑色  
	                    setColor(parentOf(x), BLACK);
	                  //将X的父节点的父节点（G）设置红色  
	                    setColor(parentOf(parentOf(x)), RED);
	                    //以X的父节点的父节点（G）为中心右旋转  
	                    rotateRight(parentOf(parentOf(x)));
	                }
	            } 
	        	//如果X的父节点（P）是其父节点的父节点（G）的右节点  
	        	else {
	        		 //获取X的叔节点（U）  
	                Entry<K,V> y = leftOf(parentOf(parentOf(x)));
	                //如果X的叔节点（U） 为红色（情况三）  
	                if (colorOf(y) == RED) {  
                        //将X的父节点（P）设置为黑色  
                        setColor(parentOf(x), BLACK);  
                        //将X的叔节点（U）设置为黑色  
                        setColor(y, BLACK);  
                        //将X的父节点的父节点（G）设置红色  
                        setColor(parentOf(parentOf(x)), RED);  
                        x = parentOf(parentOf(x));  
                    }    
	                //如果X的叔节点（U为黑色）；这里会存在两种情况（情况四、情况五）  
                    else {  
                        //如果X节点为其父节点（P）的右子树，则进行左旋转（情况四）  
                        if (x == leftOf(parentOf(x))) {  
                            //将X的父节点作为X  
                            x = parentOf(x);  
                           //右旋转  
                            rotateRight(x);  
                        }  
                        //（情况五）  
                        //将X的父节点（P）设置为黑色  
                        setColor(parentOf(x), BLACK);  
                        //将X的父节点的父节点（G）设置红色  
                        setColor(parentOf(parentOf(x)), RED);  
                        //以X的父节点的父节点（G）为中心右旋转  
                        rotateLeft(parentOf(parentOf(x)));  
	                 }
	              }
	        }
	        //将根节点G强制设置为黑色  
	        root.color = BLACK;
	    }

	    /**
	     * 删除结点 p ，删除结点p的原理：将p所在子树的叶子结点替代该结点值，删除 该叶子结点，
	     */
	    rivate void deleteEntry(Entry<K,V> p) {  
	        modCount++;      //修改次数 +1  
	        size--;          //元素个数 -1  

	        /* 
	         * 被删除节点的左子树和右子树都不为空，那么就用 p节点的中序后继节点代替 p 节点 
	         * successor(P)方法为寻找P的替代节点。规则是右分支最左边，或者 左分支最右边的节点 
	         * ---------------------（1） 
	         */  
	        if (p.left != null && p.right != null) {    
	            Entry<K,V> s = successor(p);  
	            p.key = s.key;  
	            p.value = s.value;  
	            p = s;  
	        }  

	        //replacement为替代节点，如果P的左子树存在那么就用左子树替代，否则用右子树替代  
	        Entry<K,V> replacement = (p.left != null ? p.left : p.right);  

	        /* 
	         * 删除节点，分为上面提到的三种情况 
	         * -----------------------（2） 
	         */  
	        //如果替代节点不为空  
	        if (replacement != null) {  
	            replacement.parent = p.parent;  
	            /* 
	             *replacement来替代P节点 
	             */  
	            //若P没有父节点，则跟节点直接变成replacement  
	            if (p.parent == null)  
	                root = replacement;  
	            //如果P为左节点，则用replacement来替代为左节点  
	            else if (p == p.parent.left)  
	                p.parent.left  = replacement;  
	          //如果P为右节点，则用replacement来替代为右节点  
	            else  
	                p.parent.right = replacement;  

	            //同时将P节点从这棵树中剔除掉  
	            p.left = p.right = p.parent = null;  

	            /* 
	             * 若P为红色直接删除，红黑树保持平衡 
	             * 但是若P为黑色，则需要调整红黑树使其保持平衡 
	             */  
	            if (p.color == BLACK)  
	                fixAfterDeletion(replacement);  
	        } else if (p.parent == null) {     //p没有父节点，表示为P根节点，直接删除即可  
	            root = null;  
	        } else {      //P节点不存在子节点，直接删除即可  
	            if (p.color == BLACK)         //如果P节点的颜色为黑色，对红黑树进行调整  
	                fixAfterDeletion(p);  

	            //删除P节点  
	            if (p.parent != null) {  
	                if (p == p.parent.left)  
	                    p.parent.left = null;  
	                else if (p == p.parent.right)  
	                    p.parent.right = null;  
	                p.parent = null;  
	            }  
	        }  
	    } 

	    /** From CLR */
	    /**  
	     * 删除结点后，调整为红黑树
	     * */
	    private void fixAfterDeletion(Entry<K,V> x) {  
	        // 删除节点需要一直迭代，知道 直到 x 不是根节点，且 x 的颜色是黑色  
	        while (x != root && colorOf(x) == BLACK) {  
	            if (x == leftOf(parentOf(x))) {      //若X节点为左节点  
	                //获取其兄弟节点  
	                Entry<K,V> sib = rightOf(parentOf(x));  

	                /* 
	                 * 如果兄弟节点为红色----（情况3.1） 
	                 * 策略：改变W、P的颜色，然后进行一次左旋转 
	                 */  
	                if (colorOf(sib) == RED) {       
	                    setColor(sib, BLACK);       
	                    setColor(parentOf(x), RED);    
	                    rotateLeft(parentOf(x));  
	                    sib = rightOf(parentOf(x));  
	                }  

	                /* 
	                 * 若兄弟节点的两个子节点都为黑色----（情况3.2） 
	                 * 策略：将兄弟节点编程红色 
	                 */  
	                if (colorOf(leftOf(sib))  == BLACK &&  
	                    colorOf(rightOf(sib)) == BLACK) {  
	                    setColor(sib, RED);  
	                    x = parentOf(x);  
	                }   
	                else {  
	                    /* 
	                     * 如果兄弟节点只有右子树为黑色----（情况3.3） 
	                     * 策略：将兄弟节点与其左子树进行颜色互换然后进行右转 
	                     * 这时情况会转变为3.4 
	                     */  
	                    if (colorOf(rightOf(sib)) == BLACK) {  
	                        setColor(leftOf(sib), BLACK);  
	                        setColor(sib, RED);  
	                        rotateRight(sib);  
	                        sib = rightOf(parentOf(x));  
	                    }  
	                    /* 
	                     *----情况3.4 
	                     *策略：交换兄弟节点和父节点的颜色， 
	                     *同时将兄弟节点右子树设置为黑色，最后左旋转 
	                     */  
	                    setColor(sib, colorOf(parentOf(x)));  
	                    setColor(parentOf(x), BLACK);  
	                    setColor(rightOf(sib), BLACK);  
	                    rotateLeft(parentOf(x));  
	                    x = root;  
	                }  
	            }   

	            /** 
	             * X节点为右节点与其为做节点处理过程差不多，这里就不在累述了 
	             */  
	            else {  
	                Entry<K,V> sib = leftOf(parentOf(x));  

	                if (colorOf(sib) == RED) {  
	                    setColor(sib, BLACK);  
	                    setColor(parentOf(x), RED);  
	                    rotateRight(parentOf(x));  
	                    sib = leftOf(parentOf(x));  
	                }  

	                if (colorOf(rightOf(sib)) == BLACK &&  
	                    colorOf(leftOf(sib)) == BLACK) {  
	                    setColor(sib, RED);  
	                    x = parentOf(x);  
	                } else {  
	                    if (colorOf(leftOf(sib)) == BLACK) {  
	                        setColor(rightOf(sib), BLACK);  
	                        setColor(sib, RED);  
	                        rotateLeft(sib);  
	                        sib = leftOf(parentOf(x));  
	                    }  
	                    setColor(sib, colorOf(parentOf(x)));  
	                    setColor(parentOf(x), BLACK);  
	                    setColor(leftOf(sib), BLACK);  
	                    rotateRight(parentOf(x));  
	                    x = root;  
	                }  
	            }  
	        }  

	        setColor(x, BLACK);  
	    }  
	    private static final long serialVersionUID = 919286545866124006L;

	    /**
	     * Save the state of the {@code TreeMap} instance to a stream (i.e.,
	     * serialize it).
	     *
	     * @serialData The <em>size</em> of the TreeMap (the number of key-value
	     *             mappings) is emitted (int), followed by the key (Object)
	     *             and value (Object) for each key-value mapping represented
	     *             by the TreeMap. The key-value mappings are emitted in
	     *             key-order (as determined by the TreeMap's Comparator,
	     *             or by the keys' natural ordering if the TreeMap has no
	     *             Comparator).
	     */
	    private void writeObject(java.io.ObjectOutputStream s)
	        throws java.io.IOException {
	        // Write out the Comparator and any hidden stuff
	        s.defaultWriteObject();

	        // Write out size (number of Mappings)
	        s.writeInt(size);

	        // Write out keys and values (alternating)
	        for (Iterator<Map.Entry<K,V>> i = entrySet().iterator(); i.hasNext(); ) {
	            Map.Entry<K,V> e = i.next();
	            s.writeObject(e.getKey());
	            s.writeObject(e.getValue());
	        }
	    }

	    /**
	     * Reconstitute the {@code TreeMap} instance from a stream (i.e.,
	     * deserialize it).
	     */
	    private void readObject(final java.io.ObjectInputStream s)
	        throws java.io.IOException, ClassNotFoundException {
	        // Read in the Comparator and any hidden stuff
	        s.defaultReadObject();

	        // Read in size
	        int size = s.readInt();

	        buildFromSorted(size, null, s, null);
	    }

	    /** Intended to be called only from TreeSet.readObject */
	    void readTreeSet(int size, java.io.ObjectInputStream s, V defaultVal)
	        throws java.io.IOException, ClassNotFoundException {
	        buildFromSorted(size, null, s, defaultVal);
	    }

	    /** Intended to be called only from TreeSet.addAll */
	    void addAllForTreeSet(SortedSet<? extends K> set, V defaultVal) {
	        try {
	            buildFromSorted(set.size(), set.iterator(), null, defaultVal);
	        } catch (java.io.IOException cannotHappen) {
	        } catch (ClassNotFoundException cannotHappen) {
	        }
	    }


	    /**
	     * Linear time tree building algorithm from sorted data.  Can accept keys
	     * and/or values from iterator or stream. This leads to too many
	     * parameters, but seems better than alternatives.  The four formats
	     * that this method accepts are:
	     *
	     *    1) An iterator of Map.Entries.  (it != null, defaultVal == null).
	     *    2) An iterator of keys.         (it != null, defaultVal != null).
	     *    3) A stream of alternating serialized keys and values.
	     *                                   (it == null, defaultVal == null).
	     *    4) A stream of serialized keys. (it == null, defaultVal != null).
	     *
	     * It is assumed that the comparator of the TreeMap is already set prior
	     * to calling this method.
	     *
	     * @param size the number of keys (or key-value pairs) to be read from
	     *        the iterator or stream
	     * @param it If non-null, new entries are created from entries
	     *        or keys read from this iterator.
	     * @param str If non-null, new entries are created from keys and
	     *        possibly values read from this stream in serialized form.
	     *        Exactly one of it and str should be non-null.
	     * @param defaultVal if non-null, this default value is used for
	     *        each value in the map.  If null, each value is read from
	     *        iterator or stream, as described above.
	     * @throws IOException propagated from stream reads. This cannot
	     *         occur if str is null.
	     * @throws ClassNotFoundException propagated from readObject.
	     *         This cannot occur if str is null.
	     */
	    private void buildFromSorted(int size, Iterator it,
	                                 java.io.ObjectInputStream str,
	                                 V defaultVal)
	        throws  java.io.IOException, ClassNotFoundException {
	        this.size = size;
	        root = buildFromSorted(0, 0, size-1, computeRedLevel(size),
	                               it, str, defaultVal);
	    }

	    /**
	     * Recursive "helper method" that does the real work of the
	     * previous method.  Identically named parameters have
	     * identical definitions.  Additional parameters are documented below.
	     * It is assumed that the comparator and size fields of the TreeMap are
	     * already set prior to calling this method.  (It ignores both fields.)
	     *
	     * @param level the current level of tree. Initial call should be 0.
	     * @param lo the first element index of this subtree. Initial should be 0.
	     * @param hi the last element index of this subtree.  Initial should be
	     *        size-1.
	     * @param redLevel the level at which nodes should be red.
	     *        Must be equal to computeRedLevel for tree of this size.
	     */
	    private final Entry<K,V> buildFromSorted(int level, int lo, int hi,
	                                             int redLevel,
	                                             Iterator it,
	                                             java.io.ObjectInputStream str,
	                                             V defaultVal)
	        throws  java.io.IOException, ClassNotFoundException {
	        /*
	         * Strategy: The root is the middlemost element. To get to it, we
	         * have to first recursively construct the entire left subtree,
	         * so as to grab all of its elements. We can then proceed with right
	         * subtree.
	         *
	         * The lo and hi arguments are the minimum and maximum
	         * indices to pull out of the iterator or stream for current subtree.
	         * They are not actually indexed, we just proceed sequentially,
	         * ensuring that items are extracted in corresponding order.
	         */

	        if (hi < lo) return null;

	        int mid = (lo + hi) >>> 1;

	        Entry<K,V> left  = null;
	        if (lo < mid)
	            left = buildFromSorted(level+1, lo, mid - 1, redLevel,
	                                   it, str, defaultVal);

	        // extract key and/or value from iterator or stream
	        K key;
	        V value;
	        if (it != null) {
	            if (defaultVal==null) {
	                Map.Entry<K,V> entry = (Map.Entry<K,V>)it.next();
	                key = entry.getKey();
	                value = entry.getValue();
	            } else {
	                key = (K)it.next();
	                value = defaultVal;
	            }
	        } else { // use stream
	            key = (K) str.readObject();
	            value = (defaultVal != null ? defaultVal : (V) str.readObject());
	        }

	        Entry<K,V> middle =  new Entry<>(key, value, null);

	        // color nodes in non-full bottommost level red
	        if (level == redLevel)
	            middle.color = RED;

	        if (left != null) {
	            middle.left = left;
	            left.parent = middle;
	        }

	        if (mid < hi) {
	            Entry<K,V> right = buildFromSorted(level+1, mid+1, hi, redLevel,
	                                               it, str, defaultVal);
	            middle.right = right;
	            right.parent = middle;
	        }

	        return middle;
	    }

	    /**
	     * Find the level down to which to assign all nodes BLACK.  This is the
	     * last `full' level of the complete binary tree produced by
	     * buildTree. The remaining nodes are colored RED. (This makes a `nice'
	     * set of color assignments wrt future insertions.) This level number is
	     * computed by finding the number of splits needed to reach the zeroeth
	     * node.  (The answer is ~lg(N), but in any case must be computed by same
	     * quick O(lg(N)) loop.)
	     */
	    private static int computeRedLevel(int sz) {
	        int level = 0;
	        for (int m = sz - 1; m >= 0; m = m / 2 - 1)
	            level++;
	        return level;
	    }
	}
