	    //与HashMap的区别是：当LinkedHashMap按访问顺序排序的时候，会将访问的当前节点移到链表尾部(头结点的前一个节点)
	    public V get(Object key) {
	        Entry<K,V> e = (Entry<K,V>)getEntry(key);
