	        //计算键的哈希值
	        int hash = hash(key);
	        //获取桶的位置
	        int i = indexFor(hash, table.length);
	        //因为表中保存的是桶中结点的头指针；所以找到对应的桶以后就可以从头指针开始进行遍历
	        for (Entry<K,V> e = table[i]; e != null; e = e.next) {
	            Object k;
	            //先判断该条链上有没有hash相同的(hash相同后再比较key值)
