        Node<E> x = node(index);//获取第index个位置处的元素
        E oldVal = x.item;//获取原index位置处的值并返回
        x.item = element;//替换
        return oldVal;
    }

    //增：将指定元素插入到指定位置处
    public void add(int index, E element) {
        checkPositionIndex(index);//检查是否越界

        if (index == size)
            linkLast(element);//若index即为链表尾部的位置，就直接在链表尾部插入
