    //获取指定位置处的结点
    Node<E> node(int index) {
        // assert isElementIndex(index);
    	//二分查找法,优化查询速率
        if (index < (size >> 1)) {//小于一半，从头找
            Node<E> x = first;
            for (int i = 0; i < index; i++)
                x = x.next;
            return x;
        } else {//大于一半，从尾部找
            Node<E> x = last;
            for (int i = size - 1; i > index; i--)
                x = x.prev;
            return x;
        }
    }

    //返回元素o在链表中第一次出现的位置；没有则返回-1
    public int indexOf(Object o) {
