	    //返回指定位置的元素
	    @SuppressWarnings("unchecked")
	    E elementData(int index) {
	        return (E) elementData[index];
	    }

	   //返回集合中指定位置的元素
	    public E get(int index) {
	        rangeCheck(index);//确保index小于集合容量
	        return elementData(index);
	    }

	    //将指定元素element插入到指定位置index处
	    //注意：返回值是原集合中index处的元素：oldValue
	    public E set(int index, E element) {
	        rangeCheck(index);

	        E oldValue = elementData(index);
	        elementData[index] = element;
	        return oldValue;
	    }

	   //添加元素到集合的尾部--添加成功返回true
	    public boolean add(E e) {
	        ensureCapacityInternal(size + 1);  // Increments modCount!!
//	        elementData[size++] = e;/添加元素到集合的尾部
	        return true;
	    }

	    //将元素插入到指定位置处，位置上的原元素及之后元素整体右移
	    public void add(int index, E element) {
	        rangeCheckForAdd(index);

	        ensureCapacityInternal(size + 1);  // Increments modCount!!
	        System.arraycopy(elementData, index, elementData, index + 1,
	                         size - index);//将原数组elementData从index开始的(size - index)段的 元素
	        							   //复制到数组elementData的index+1处(即后移一位)
	        elementData[index] = element;
	        size++;
	    }

	    //从集合中移除指定位置处的元素；
	    //原理：指定位置Index后的所有元素左移一位(覆盖index处所在的元素)
	    //返回的是index处所在的原元素
	    public E remove(int index) {
	        rangeCheck(index);

	        modCount++;
	        E oldValue = elementData(index);

	        int numMoved = size - index - 1;//计算从 index处后的元素个数(即将要左移的元素个数)
	        if (numMoved > 0)
	            System.arraycopy(elementData, index+1, elementData, index,
	                             numMoved);//将原数组elementData从index+1处，长度为numMoved长的所有元素
	        							   //复制到原数组elementData从index处(即左移一位)
	        elementData[--size] = null; // clear to let GC do its work,最后空的一位设置为null,交给GC处理

	        return oldValue;
	    }

	    //移除集合中第一次出现的元素o，没有返回false
	    public boolean remove(Object o) {
	        if (o == null) {
	            for (int index = 0; index < size; index++)
	                if (elementData[index] == null) {
	                    fastRemove(index);//此方法原理同上E remove(int index)
	                    return true;
	                }
	        } else {
	            for (int index = 0; index < size; index++)
	                if (o.equals(elementData[index])) {
	                    fastRemove(index);
	                    return true;
	                }
	        }
	        return false;
	    }

	    //E remove(int index)的一个快速实现，不返回值
	    private void fastRemove(int index) {
	        modCount++;
	        int numMoved = size - index - 1;
	        if (numMoved > 0)
	            System.arraycopy(elementData, index+1, elementData, index,
	                             numMoved);
	        elementData[--size] = null; // clear to let GC do its work
	    }

	    //清空集合
	    //原理：将所有元素置为null，大小置0 
	    public void clear() {
	        modCount++;

	        // clear to let GC do its work
	        for (int i = 0; i < size; i++)
	            elementData[i] = null;

	        size = 0;
	    }

	   //将集合c中元素添加到原集合尾部
	    public boolean addAll(Collection<? extends E> c) {
	        Object[] a = c.toArray();
	        int numNew = a.length;
	        ensureCapacityInternal(size + numNew);  // Increments modCount
	        System.arraycopy(a, 0, elementData, size, numNew);
	        size += numNew;
	        return numNew != 0;
	    }

	    //将集合中元素添加到原集合指定位置处
	    public boolean addAll(int index, Collection<? extends E> c) {
	        rangeCheckForAdd(index);

	        Object[] a = c.toArray();
	        int numNew = a.length;
	        ensureCapacityInternal(size + numNew);  // Increments modCount

	        int numMoved = size - index;
	        if (numMoved > 0)
	            System.arraycopy(elementData, index, elementData, index + numNew,
	                             numMoved);//先将原集合index处及之后元素复制到index + numNew处，即整体右移numMoved

	        System.arraycopy(a, 0, elementData, index, numNew);
	        size += numNew;
	        return numNew != 0;
	    }

	    //移除指定位置处的元素(包括fromIndex，不包括toIndex)
	    protected void removeRange(int fromIndex, int toIndex) {
	        modCount++;
	        int numMoved = size - toIndex;
	        System.arraycopy(elementData, toIndex, elementData, fromIndex,
	                         numMoved);//将原集合中从toIndex处元素及之后的元素复制到fromIndex处，及左移
	        // clear to let GC do its work
	        int newSize = size - (toIndex-fromIndex);
	        for (int i = newSize; i < size; i++) {
	            elementData[i] = null;
	        }
	        size = newSize;
	    }

	    //检查index是否在范围内
	    private void rangeCheck(int index) {
	        if (index >= size)
	            throw new IndexOutOfBoundsException(outOfBoundsMsg(index));
	    }

	    private void rangeCheckForAdd(int index) {
	        if (index > size || index < 0)
	            throw new IndexOutOfBoundsException(outOfBoundsMsg(index));
	    }

	    //创建一个范围超标的具体信息
	    private String outOfBoundsMsg(int index) {
	        return "Index: "+index+", Size: "+size;
	    }

	    //删除原集合中与c集合相同的元素
	    public boolean removeAll(Collection<?> c) {
	        return batchRemove(c, false);
	    }

	    //保留与c集合相同的元素；即删除与c集合不同的元素
	    public boolean retainAll(Collection<?> c) {
	        return batchRemove(c, true);
	    }

	    //批量删除
	    private boolean batchRemove(Collection<?> c, boolean complement) {
	        final Object[] elementData = this.elementData;
	        int r = 0, w = 0;
	        boolean modified = false;
	        try {
	            for (; r < size; r++)
	                if (c.contains(elementData[r]) == complement)
	                    elementData[w++] = elementData[r];
	        } finally {
	            // Preserve behavioral compatibility with AbstractCollection,
	            // even if c.contains() throws.
	            if (r != size) {
	                System.arraycopy(elementData, r,
	                                 elementData, w,
	                                 size - r);
	                w += size - r;
	            }
	            if (w != size) {
	                // clear to let GC do its work
	                for (int i = w; i < size; i++)
	                    elementData[i] = null;
	                modCount += size - w;
	                size = w;
	                modified = true;
	            }
	        }
	        return modified;
	    }

	    //？序列化
	    private void writeObject(java.io.ObjectOutputStream s)
	        throws java.io.IOException{
	        // Write out element count, and any hidden stuff
	        int expectedModCount = modCount;
	        s.defaultWriteObject();

	        // Write out size as capacity for behavioural compatibility with clone()
	        s.writeInt(size);

	        // Write out all elements in the proper order.
	        for (int i=0; i<size; i++) {
	            s.writeObject(elementData[i]);
	        }

	        if (modCount != expectedModCount) {
	            throw new ConcurrentModificationException();
	        }
	    }

	    //？反序列化
	    private void readObject(java.io.ObjectInputStream s)
	        throws java.io.IOException, ClassNotFoundException {
	        elementData = EMPTY_ELEMENTDATA;

	        // Read in size, and any hidden stuff
	        s.defaultReadObject();

	        // Read in capacity
	        s.readInt(); // ignored

	        if (size > 0) {
	            // be like clone(), allocate array based upon size not capacity
	            ensureCapacityInternal(size);

	            Object[] a = elementData;
	            // Read in all elements in the proper order.
	            for (int i=0; i<size; i++) {
	                a[i] = s.readObject();
	            }
	        }
	    }

