import java.util.*;

public class Main{

    public static int getBottles(int num){
        //小于3，换不了汽水，返回0
        if(num < 3)
            return 0;

        int result =0;

        while(num > 2){
            //本次喝的饮料瓶数
            int drinkBottles = num / 3;
            //本次喝的汽水瓶
            result += drinkBottles;
            //本次喝的剩下的瓶数  +  喝的瓶数
            num = num % 3 + drinkBottles;

        }

        if(num == 2){
            result++;
        }

        return result;

    }



    public static void main(String[] args){
        Scanner sc = new Scanner(System.in);
        int num ;
        while(sc.hasNextInt() && ((num = sc.nextInt())!=0)){
            System.out.println(getBottles(num));
        }
        sc.close();
    }
}
