### 题目描述

开发一个坐标计算工具， A表示向左移动，D表示向右移动，W表示向上移动，S表示向下移动。从（0,0）点开始移动，从输入字符串里面读取一些坐标，并将最终输入结果输出到输出文件里面。

输入：

合法坐标为A(或者D或者W或者S) + 数字（两位以内）

坐标之间以;分隔。

非法坐标点需要进行丢弃。如AA10;  A1A;  $%$;  YAD; 等。

下面是一个简单的例子 如：

A10;S20;W10;D30;X;A1A;B10A11;;A10;

处理过程：

起点（0,0）

+   A10   =  （-10,0）

+   S20   =  (-10,-20)

+   W10  =  (-10,-10)

+   D30  =  (20,-10)

+   x    =  无效

+   A1A   =  无效

+   B10A11   =  无效

+  一个空 不影响

+   A10  =  (10,-10)

结果 （10， -10）



###### 输入描述:

```
一行字符串
```




###### 输出描述:

```
最终坐标，以,分隔
```



###### 输入例子:

```
A10;S20;W10;D30;X;A1A;B10A11;;A10;
```



###### 输出例子:

```
10,-10
```

```
```
import java.util.Scanner;

/**
 *【题17】 坐标移动:   方向：       A<☜     D>☞    W^☝         S!☟
 * A10;S20;W10;D30;X;A1A;B10A11;;A10; 
起点（0,0）
+   A10   =  （-10,0）
+   S20   =  (-10,-20)
+   W10  =  (-10,-10) 
+   D30  =  (20,-10) 
+   x    =  无效
+   A1A   =  无效
+   B10A11   =  无效
+  一个空 不影响
+   A10  =  (10,-10)  
结果 （10， -10）
 * @author WGS
 */
public class Main {

	public static String calculateLocations(String str){
		StringBuilder sb=new StringBuilder(128);
		if(str ==null ||str.length() <=0)
			return " ";
		String[] input=str.split(";");
		int X=0;
		int Y=0;
		//A10
		for(int i=0;i<input.length;i++){
			//1 长度验证：必须长度小于等于3：A2，A10;D22...，空格或者不法输入如A12#..就可直接排除
			if(input[i].length()<=3 && (!input[i].equals(""))){
					char firstChar=input[i].charAt(0);//获取A
					String numSubStr=input[i].substring(1);//获取字母后的数字，为字符串String
					int num=0;
					//3  验证字母后的数字是否合法：必须是99以内的数字
						if(isValidNum(numSubStr)){
							num=Integer.parseInt(numSubStr);//获取10
						}else{
							num=0;
						}
						if(num >=0 && num<=99){
							//2  首字母验证及计算:不是  ADWS 的就继续：
							if(firstChar == 'A'){
								X -= num;
							}else if(firstChar == 'D'){
								X += num;
							}else if(firstChar == 'W'){
								Y+=num;
							}else if(firstChar == 'S'){
								Y-=num;
							}else{
								continue;
							}
						}	
					}
		}
		sb.append(X).append(",").append(Y);
		return sb.toString();
	}

	private static boolean isValidNum(String str){
		char[] charStr=str.toCharArray();
		for(int i=0;i<charStr.length;i++){
			if(charStr[i]< '0' || charStr[i] > '9'){
				return false;
			}
		}
		return true;
	}


	public static void main(String[] args) {

		Scanner sc=new Scanner(System.in);
		while(sc.hasNext()){
			String str=sc.nextLine();
            System.out.println(calculateLocations(str));

		}
		sc.close();

	}

}
