public class Exe10 {

	public static int largestRectangleArea(int[] height) {
		int max = 0;
		int len = height.length;
		for(int i=0; i<len; i++){
			int minHeight = height[i];
			for(int j=i; j<len; j++){
				minHeight = Math.min(minHeight, height[j]);
				max = Math.max(max, (j-i+1)*minHeight);
