   public static int getLengthOfLastWord(String str){
	       if(str==null ||str.length()<=0)
	           return 0;
	       char[] strChar=str.toCharArray();
	        int len=strChar.length;
	       char flag=1;
	       char count=0;
       	   //统计空格数，并给空格数做上标记
	       for(int i=0;i<len;i++){
