	public int TreeDepth(TreeNode pRoot)
    {
    	if(pRoot==null)
            return 0;
        //递归得到左子树深度
        int leftDep=TreeDepth(pRoot.left);
        //递归得到右子树深度
        int rightDep=TreeDepth(pRoot.right);
        //比较左右子树深度，谁大加1（根结点）即为整个树深度
        return (leftDep>rightDep)?leftDep+1:rightDep+1;
    }
}
