import java.util.ArrayList;
public class Solution {
    public int[] multiply(int[] A) {
        if(A==null ||A.length<=0)
            return A;
        int n=A.length;
        int[] front=new int[n];
        int[] back=new int[n];
        front[0]=1;
        back[n-1]=1;
        for(int i=1;i<n;i++){
            front[i]=front[i-1]*A[i-1];
            back[n-1-i]=back[n-i]*A[n-i];
        }
        for(int i=0;i<n;i++){
            front[i]*=back[i];
        }
        return front;
    }
}
