public class Solution {
    public int GetNumberOfK(int [] array , int k) {
       if(array==null||array.length<=0)
           return 0;
        int first=-1;
        int last=-1;
         //找到第一次出现的位置
        for(int i=0;i<array.length;i++){
            if(array[i]==k){
	            	first=i;
	            	break;
	         }
        }
